var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"딸아이가 입원을 했는데, 아빠가 얼굴 한 번 안 비추는 게 말이 돼?","JPN":"自分の娘が入院したというのに、一度も顔を出さないなんて、それでも父親なの？","ENG":"Your daughter's hospitalized, and you can't even drop by for a visit?","TWN":"女兒住院，身為父親，你卻一次都沒來看過她，這像話嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NONAME","text":{"KOREA":"<color=#ffd34c>간만에 프로젝트에 진척이 생겨서. 오늘도 당신 혼자 챙겨줘야 할 것 같아.</color>","JPN":"<color=#ffd34c>やっとプロジェクトが動き始めたんだ。そうあることじゃないし、今日も君に世話は頼んだぞ。</color>","ENG":"<color=#ffd34c>We've made a breakthrough in our project. So you'll have to take care of her alone for today.</color>","TWN":"<color=#ffd34c>項目難得有進展。今天也得要你照顧下她。</color>"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"누군 시간 없어? 나도 내 연구 다 제쳐두고 온 거야.","JPN":"私だって自分の研究はそっちのけでここに来ているのよ？","ENG":"And you think I've got the time? I had to shelf all my research to be here.","TWN":"誰不忙？我也是放下了手頭的研究來照顧她啊。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NONAME","text":{"KOREA":"<color=#ffd34c>정말 미안해, 다이앤.</color>","JPN":"<color=#ffd34c>本当にすまない。ダイアン。</color>","ENG":"<color=#ffd34c>I'm really sorry, Diana.</color>","TWN":"<color=#ffd34c>我很抱歉，黛安娜。</color>"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_NONAME","text":{"KOREA":"<color=#ffd34c>아이 생일 전까진 휴가 받아서 들를게.</color>","JPN":"<color=#ffd34c>あの子の誕生日までには休みを取って行けるようにするよ。</color>","ENG":"<color=#ffd34c>I'll make sure to take some time off from work before her birthday.</color>","TWN":"<color=#ffd34c>我會在孩子生日前，請假去看她的。</color>"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그래… 마음대로 해.","JPN":"はあ……好きにすれば。","ENG":"Sure... whatever.","TWN":"好……隨便你。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"이만 끊자.","JPN":"もういいわ、切るわね。","ENG":"Bye.","TWN":"我掛了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"…병실 밥은 입맛에 맞니?","JPN":"……病院の食事はどう？","ENG":"...How's the food? Do you like it?","TWN":"……醫院的食物怎麼樣？還吃得慣嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"잘 모르겠어.","JPN":"よくわからない。","ENG":"I’m not sure.","TWN":"我不知道……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그래도 잘 먹어야 건강해지지.","JPN":"でも食べないと元気にならないわよ。","ENG":"You have to eat to get better soon.","TWN":"那也得吃，這樣身體才能好得快。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"...아빠는 언제 와요?","JPN":"……お父さんはいつ来るの？","ENG":"...When is dad coming?","TWN":"……爸爸、爸爸什麼時候會來？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"네 생일날엔 꼭 오겠다고 하시네.","JPN":"誕生日には来るって。","ENG":"He promised to be here on your birthday.","TWN":"爸爸說等到你生日那天，他一定會來。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"정말?","JPN":"本当？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그래. 생일 선물로 뭘 받고 싶은지 생각해두는 건 어때?","JPN":"ええ。誕生日プレゼント、何が欲しいか考えておいたら？","ENG":"Of course. So why don't you think about what you want for your birthday present?","TWN":"當然了。所以現在不如好好想想，生日那天想要什麼禮物？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"음...","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"엄마가 나처럼 아프지 않았으면 좋겠어요.","JPN":"お母さんが私みたいに体調を崩さないでほしいかな。","ENG":"I want you to be healthy, Mommy. Unlike me.","TWN":"我想讓媽媽快點好起來，不要像我一樣。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그게… 무슨 소리니?","JPN":"うん……？　 どういうこと？","ENG":"What... do you mean by that?","TWN":"……你在說什麼呢？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"5년 전에 아빠가 날 데리고 사라졌잖아요.","JPN":"5年前。お父さんが私を連れていなくなって。","ENG":"Remember how Daddy took me and left you five years ago?","TWN":"五年前，爸爸不是帶著我一起失蹤了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"그래서 엄마도 5년 동안 아빠만 찾아다니다 나랑 똑같은 병에 걸렸고요.","JPN":"お母さんは5年間も、お父さんのことを探し回って、私と同じ病気になっちゃった。","ENG":"And you got sick with the same thing I had while looking for him for five years?","TWN":"結果媽媽找了我們五年，最後也得了和我一樣的病。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"이건 꿈이구나.","JPN":"そうか、これは夢。","ENG":"This is a dream.","TWN":"原來，是夢啊。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"하긴, 생일이 되기 전에 침식증후군이 네 목소리를 빼앗아갔으니까.","JPN":"ああ……誕生日を迎える前に、あなたは侵食症候群に声を奪われたから。","ENG":"I mean, of course, it is. The Corruption Syndrome took your voice before your birthday came.","TWN":"咳，當然了。侵蝕症候群在你生日之前就奪走了你的聲音。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"그래서 우린 헤어지는 날까지 제대로 대화도 한 번 못 나눴지.","JPN":"だからあなたとは、お別れの瞬間まで一言も言葉を交わすことができなかった。","ENG":"We couldn't even have a proper conversation until the day we had to say goodbye.","TWN":"所以，直到分離的那天，我們都沒能好好說上一句話。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"엄마…","JPN":"お母さん……","ENG":"Mommy...","TWN":"媽媽……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"네 아버지가 널 데려갈 거란 것도, 난 네가 사라질 때까지 몰랐어.","JPN":"あなたの父親が、あなたを連れ去ることも、その時になるまで知らなかった。","ENG":"I didn't even think your dad would take you away until you disappeared.","TWN":"我從未想過爸爸會把你一起帶走。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"알고 있었다면 내가 막았을 텐데.","JPN":"もし気づいていたら、止めることもできたのに。","ENG":"I would've stopped him if I had known.","TWN":"如果早點知道的話，一定會阻止他的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPRIT_FLOOR_GIRL_HOSPITAL","text":{"KOREA":"꿈에서 깨어나고 싶어요?","JPN":"お母さん……夢から目覚めたいの？","ENG":"Do you want to wake up from this dream?","TWN":"媽媽，你現在要醒了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NONAME","text":{"KOREA":"아니. 널 이렇게나마 계속 보고 싶어.","JPN":"ううん。こうしてあなたの顔が見られるだけで幸せだもの。","ENG":"No. I still want to see you. Even if it's like this.","TWN":"不。我想繼續這樣看著你。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"SPRIT_FLOOR_GIRL_HOSPITAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NONAME","face":"UNIT_IDLE"}}}}]`);export{e as default};